Question 2

2.1 Distance to US National Border (km)

# st_union dissolves ALL internal state borders → only outer boundary remains
us_border &lt;- states |&gt;
  st_union() |&gt;
  st_cast("MULTILINESTRING")

cities &lt;- cities |&gt;
  mutate(
    dist_to_border = st_distance(geometry, us_border) |&gt;
      set_units("km") |&gt;
      drop_units()
  )

cities |&gt;
  st_drop_geometry() |&gt;
  slice_max(dist_to_border, n = 5) |&gt;
  select(city, state_name, dist_to_border) |&gt;
  mutate(dist_to_border = round(dist_to_border, 1)) |&gt;
  flextable() |&gt;
  set_header_labels(
    city = "City", 
    state_name = "State", 
    dist_to_border = "Distance to National Border (km)"
  ) |&gt;
  autofit()

