2.2 Distance to Nearest State Border (km)

# st_combine keeps all geometries without dissolving → internal borders preserved
state_borders &lt;- states |&gt;
  st_combine() |&gt;
  st_cast("MULTILINESTRING")

cities &lt;- cities |&gt;
  mutate(
    dist_to_state = st_distance(geometry, state_borders) |&gt;
      set_units("km") |&gt;
      drop_units()
  )

cities |&gt;
  st_drop_geometry() |&gt;
  slice_max(dist_to_state, n = 5) |&gt;
  select(city, state_name, dist_to_state) |&gt;
  mutate(dist_to_state = round(dist_to_state, 1)) |&gt;
  flextable() |&gt;
  set_header_labels(
    city = "City",
    state_name = "State",
    dist_to_state = "Distance to Nearest State Border (km)"
  ) |&gt;
  autofit()

